class NemotronTensorProcessor(TensorProcessor):
    def __init__(self, config=None):
        super().__init__(config=config)

    # ref : https://github.com/ggerganov/llama.cpp/blob/master/convert_hf_to_gguf.py#L4666
    def process(self, weights, name, **kwargs):
        if "norm.weight" in name:
            weights = weights - 1
        return GGUFTensor(weights, name, {})

class NemotronTensorProcessor(TensorProcessor) {
  __init__(config=None) = super().__init__(config=config)
  process(weights, name, **kwargs) = weights - 1 if "norm.weight" in name else weights |> GGUFTensor(_, name, {})
}
